import React from "react";

export default function CampaignHistoryNav({ activeSection, onSectionChange, recentCount, historyCount, filter, onFilterChange }) {
  const navItems = [
    {
      id: "recent",
      name: "Recent Campaigns",
      icon: "📊",
      count: recentCount,
      description: "Last 5 campaigns"
    },
    {
      id: "history",
      name: "Campaign History",
      icon: "📋",
      count: historyCount,
      description: "All older campaigns"
    },
    {
      id: "analytics",
      name: "Analytics",
      icon: "📈",
      count: null,
      description: "Campaign performance"
    },
    {
      id: "templates",
      name: "Templates",
      icon: "📝",
      count: null,
      description: "Message templates"
    },
    {
      id: "scheduled",
      name: "Scheduled",
      icon: "⏰",
      count: null,
      description: "Upcoming campaigns"
    }
  ];

  const filterOptions = [
    { value: "all", label: "All Campaigns", icon: "🌐" },
    { value: "whatsapp", label: "WhatsApp", icon: "💬" },
    { value: "sms", label: "SMS", icon: "📱" }
  ];

  return (
    <div className="w-64 bg-white rounded-lg shadow-lg p-4 mr-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4 pb-2 border-b">
        Campaign Navigation
      </h3>

      {/* Main Navigation */}
      <div className="space-y-2 mb-6">
        {navItems.map((item) => (
          <button
            key={item.id}
            onClick={() => item.id === "recent" || item.id === "history" ? onSectionChange(item.id) : alert(`${item.name} coming soon!`)}
            className={`w-full text-left px-3 py-3 rounded-lg transition-all duration-200 flex items-center gap-3 ${
              activeSection === item.id
                ? "bg-blue-500 text-white shadow-md"
                : "hover:bg-gray-100 text-gray-700"
            } ${item.id === "analytics" || item.id === "templates" || item.id === "scheduled" ? "opacity-60 cursor-not-allowed" : ""}`}
          >
            <span className="text-lg">{item.icon}</span>
            <div className="flex-1">
              <div className="font-medium">{item.name}</div>
              <div className="text-xs text-gray-500">{item.description}</div>
            </div>
            {item.count !== null && (
              <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                activeSection === item.id
                  ? "bg-blue-600 text-white"
                  : "bg-gray-200 text-gray-600"
              }`}>
                {item.count}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* Filter Section */}
      <div className="border-t pt-4">
        <h4 className="text-sm font-semibold text-gray-700 mb-3">Filter by Type</h4>
        <div className="space-y-1">
          {filterOptions.map((option) => (
            <button
              key={option.value}
              onClick={() => onFilterChange(option.value)}
              className={`w-full text-left px-3 py-2 rounded-md transition-colors duration-200 flex items-center gap-2 ${
                filter === option.value
                  ? "bg-blue-100 text-blue-700 border border-blue-300"
                  : "hover:bg-gray-50 text-gray-700"
              }`}
            >
              <span>{option.icon}</span>
              <span className="text-sm">{option.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Quick Stats */}
      <div className="border-t pt-4 mt-4">
        <h4 className="text-sm font-semibold text-gray-700 mb-3">Quick Stats</h4>
        <div className="grid grid-cols-2 gap-2 text-xs">
          <div className="bg-gray-50 p-2 rounded">
            <div className="text-gray-500">Total</div>
            <div className="font-semibold">{recentCount + historyCount}</div>
          </div>
          <div className="bg-green-50 p-2 rounded">
            <div className="text-gray-500">Active</div>
            <div className="font-semibold text-green-600">{recentCount}</div>
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="border-t pt-4 mt-4">
        <h4 className="text-sm font-semibold text-gray-700 mb-3">Quick Actions</h4>
        <div className="space-y-2">
          <button className="w-full bg-green-500 hover:bg-green-600 text-white px-3 py-2 rounded-md text-sm font-medium transition-colors duration-200">
            ➕ Create New Campaign
          </button>
          <button className="w-full bg-blue-500 hover:bg-blue-600 text-white px-3 py-2 rounded-md text-sm font-medium transition-colors duration-200">
            📊 Export Report
          </button>
        </div>
      </div>
    </div>
  );
}
